CREATE TABLE IF NOT EXISTS t_p49497665_pmsuite_management_s.projects (id SERIAL PRIMARY KEY, name VARCHAR(300) NOT NULL, status VARCHAR(20) DEFAULT 'active', progress INTEGER DEFAULT 0, lead VARCHAR(200), deadline VARCHAR(50), priority VARCHAR(20) DEFAULT 'medium', tasks_total INTEGER DEFAULT 0, tasks_done INTEGER DEFAULT 0, created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW());